sql:
SELECT COUNT(donation_id) AS total_donations
FROM donations
WHERE STRFTIME('%Y', date) = '2022';

SELECT name, net_worth
FROM donors
ORDER BY net_worth DESC;

SELECT name, net_worth
FROM donors
WHERE net_worth > (SELECT AVG(net_worth) FROM donors);

SELECT donor_id, TYPEOF(net_worth) AS net_worth_type
FROM donors
WHERE donor_id = 1;

external_knowledge:
- "philanthropic titans" refers to individuals with high net worth engaging in generous charitable giving;
- "financial reservoirs" refers to the net worth of the donors;
- "magnitude of their generosity" refers to the total amount donated by each donor;
- "charitable waves in the ocean of donations" is a metaphor for the cumulative donations made towards various charitable causes.

sql:
SELECT MAX(d.net_worth) AS max_net_worth
FROM donors d
INNER JOIN giving_goals gg ON d.donor_id = gg.donor_id;

SELECT name, net_worth
FROM donors
WHERE net_worth = (SELECT MAX(net_worth) FROM donors);

SELECT philanthropic_history
FROM donor_profiles
WHERE donor_id = 1;
